export function graphSequencer(t,s=[...t.keys()]){const e=new Map;for(const s of t.keys())e.set(s,[]);const n=new Set(s),o=new Set,c=new Map;for(const[s,f]of t){c.set(s,0);for(const t of f)n.has(s)&&n.has(t)&&(u(s,1),e.get(t).push(s));n.has(s)||o.add(s)}const f=[],h=[];let r=!0;for(;n.size;){const t=[];let s=Number.MAX_SAFE_INTEGER;for(const e of n){const n=c.get(e);0===n&&t.push(e),s=Math.min(s,n)}if(0===s)t.forEach(a),f.push(t);else{const t=[];for(const s of n){const e=g(s);e.length&&(h.push(e),e.forEach(a),t.push(...e),e.length>1&&(r=!1))}f.push(t)}}return{safe:r,chunks:f,cycles:h};function u(t,s){const e=c.get(t)??0;c.set(t,e+s)}function a(t){for(const s of e.get(t))u(s,-1);o.add(t),n.delete(t)}function g(s){const e=[[s,[s]]],n=new Set,c=[];for(;e.length;){const[f,h]=e.shift(),r=t.get(f);if(r)for(const t of r)t!==s?o.has(t)||n.has(t)||(n.add(t),e.push([t,[...h,t]])):(n.add(t),c.push([...h]))}return c.length?(c.sort((t,s)=>s.length-t.length),c[0]):[]}}